#!/usr/bin/env python3
"""Restore a directory produced by compress.py back to its original layout."""

from __future__ import annotations

import hashlib
import json
import os
import shutil
import stat
import sys
import tempfile
from pathlib import Path


META_NAME = "reshard-meta.json"
PAYLOAD_DIR = "payload"
MANIFEST_DIR = "manifest"


def fail(message: str) -> None:
    print(f"decompress.py: {message}", file=sys.stderr)
    raise SystemExit(1)


def safe_relative_path(raw_path: str) -> Path:
    path = Path(raw_path)
    if path.is_absolute() or ".." in path.parts:
        fail(f"unsafe relative path in manifest: {raw_path}")
    return path


def read_json(path: Path) -> object:
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except FileNotFoundError:
        fail(f"missing required file: {path}")
    except json.JSONDecodeError as exc:
        fail(f"invalid JSON in {path}: {exc}")


def load_manifest(root: Path) -> dict[str, object]:
    meta = read_json(root / META_NAME)
    if not isinstance(meta, dict) or meta.get("version") != 1:
        fail("unsupported or missing reshard metadata")

    manifest_chunks = meta.get("manifest_chunks")
    if not isinstance(manifest_chunks, list) or not manifest_chunks:
        fail("metadata does not contain manifest chunks")

    parts: list[bytes] = []
    for raw_path in manifest_chunks:
        if not isinstance(raw_path, str):
            fail("manifest chunk path must be a string")
        rel_path = safe_relative_path(raw_path)
        chunk_path = root / MANIFEST_DIR / rel_path
        try:
            parts.append(chunk_path.read_bytes())
        except FileNotFoundError:
            fail(f"missing manifest chunk: {chunk_path}")

    try:
        manifest = json.loads(b"".join(parts).decode("utf-8"))
    except (UnicodeDecodeError, json.JSONDecodeError) as exc:
        fail(f"invalid manifest: {exc}")

    if not isinstance(manifest, dict) or manifest.get("version") != 1:
        fail("unsupported manifest version")
    return manifest


def restore_empty_dirs(tmp_root: Path, manifest: dict[str, object]) -> None:
    empty_dirs = manifest.get("empty_dirs", [])
    if not isinstance(empty_dirs, list):
        fail("manifest empty_dirs must be a list")
    for raw_path in empty_dirs:
        if not isinstance(raw_path, str):
            fail("empty directory path must be a string")
        (tmp_root / safe_relative_path(raw_path)).mkdir(parents=True, exist_ok=True)


def restore_files(root: Path, tmp_root: Path, manifest: dict[str, object]) -> None:
    files = manifest.get("files")
    if not isinstance(files, list):
        fail("manifest files must be a list")

    for entry in files:
        if not isinstance(entry, dict):
            fail("file entry must be an object")

        raw_path = entry.get("path")
        chunks = entry.get("chunks")
        expected_sha256 = entry.get("sha256")
        expected_size = entry.get("size")
        mode = entry.get("mode")

        if not isinstance(raw_path, str):
            fail("file path must be a string")
        if not isinstance(chunks, list) or not chunks:
            fail(f"file entry has no chunks: {raw_path}")
        if not isinstance(expected_sha256, str) or not isinstance(expected_size, int):
            fail(f"file entry is missing checksum or size: {raw_path}")

        target = tmp_root / safe_relative_path(raw_path)
        target.parent.mkdir(parents=True, exist_ok=True)
        sha256 = hashlib.sha256()
        written = 0

        with target.open("wb") as out:
            for raw_chunk in chunks:
                if not isinstance(raw_chunk, str):
                    fail(f"chunk path must be a string for {raw_path}")
                chunk_path = root / PAYLOAD_DIR / safe_relative_path(raw_chunk)
                try:
                    data = chunk_path.read_bytes()
                except FileNotFoundError:
                    fail(f"missing payload chunk: {chunk_path}")
                sha256.update(data)
                written += len(data)
                out.write(data)

        if written != expected_size:
            fail(f"size mismatch for {raw_path}: expected {expected_size}, wrote {written}")
        if sha256.hexdigest() != expected_sha256:
            fail(f"checksum mismatch for {raw_path}")
        if isinstance(mode, int):
            os.chmod(target, stat.S_IMODE(mode))


def replace_root_with_tmp(root: Path, tmp_root: Path) -> None:
    for child in root.iterdir():
        if child == tmp_root:
            continue
        if child.is_dir() and not child.is_symlink():
            shutil.rmtree(child)
        else:
            child.unlink()

    for child in tmp_root.iterdir():
        shutil.move(str(child), root / child.name)
    tmp_root.rmdir()


def main(argv: list[str]) -> int:
    if len(argv) != 2:
        fail("usage: python /app/decompress.py <resharded_dir>")

    root = Path(argv[1])
    if not root.is_dir():
        fail(f"resharded directory does not exist: {root}")

    manifest = load_manifest(root)
    tmp_root = Path(tempfile.mkdtemp(prefix=".decompress-", dir=root))
    try:
        restore_empty_dirs(tmp_root, manifest)
        restore_files(root, tmp_root, manifest)
        replace_root_with_tmp(root, tmp_root)
    except Exception:
        if tmp_root.exists():
            shutil.rmtree(tmp_root)
        raise

    print(f"restored original layout in {root}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main(sys.argv))

